TriggerOraclev10g.body:
DECLARE envbq_status number; valor_envbq_update number; vro_error tkr_errores%ROWTYPE; BEGIN -- En el caso de INSERT IF INSERTING THEN
SELECT (SELECT ENVIO_BQ FROM TKRBQ_ENCUESTA_DOCTOR WHERE ID = :NEW.ID AND ENVIO_BQ != 1) INTO envbq_status FROM DUAL;
IF envbq_status IS NOT NULL THEN DELETE TKRBQ_ENCUESTA_DOCTOR WHERE ID = :NEW.ID AND ENVIO_BQ != 1; END IF;
INSERT INTO TKRBQ_ENCUESTA_DOCTOR ( ENVIO_BQ, ID, ID_CONSULTA, ID_USUARIO, DURACION_CONSULTA, SATISFACCION_PRODUCTO, EXPERIMENTO_DIFICULTADES, COMENTARIOS, FECHA_ENCUESTA, RECOMIENDA_SERVICIO, ID_INTERCONSULTA, OTRA_DIFICULTAD, FECHA_CREACION ) VALUES ( 0, -- ENVIO_BQ por defecto :NEW.ID, :NEW.ID_CONSULTA, :NEW.ID_USUARIO, :NEW.DURACION_CONSULTA, :NEW.SATISFACCION_PRODUCTO, :NEW.EXPERIMENTO_DIFICULTADES, :NEW.COMENTARIOS, :NEW.FECHA_ENCUESTA, :NEW.RECOMIENDA_SERVICIO, :NEW.ID_INTERCONSULTA, :NEW.OTRA_DIFICULTAD, :NEW.FECHA_CREACION ); END IF;
-- En el caso de UPDATE IF UPDATING THEN SELECT (SELECT ENVIO_BQ FROM TKRBQ_ENCUESTA_DOCTOR WHERE ID = :NEW.ID AND ENVIO_BQ != 1 AND ROWNUM <= 1) INTO envbq_status FROM DUAL;
IF envbq_status IS NULL THEN
INSERT INTO TKRBQ_ENCUESTA_DOCTOR ( ENVIO_BQ, ID, ID_CONSULTA, ID_USUARIO, DURACION_CONSULTA, SATISFACCION_PRODUCTO, EXPERIMENTO_DIFICULTADES, COMENTARIOS, FECHA_ENCUESTA, RECOMIENDA_SERVICIO, ID_INTERCONSULTA, OTRA_DIFICULTAD, FECHA_CREACION ) VALUES ( 2, -- ENVIO_BQ por defecto :NEW.ID, :NEW.ID_CONSULTA, :NEW.ID_USUARIO, :NEW.DURACION_CONSULTA, :NEW.SATISFACCION_PRODUCTO, :NEW.EXPERIMENTO_DIFICULTADES, :NEW.COMENTARIOS, :NEW.FECHA_ENCUESTA, :NEW.RECOMIENDA_SERVICIO, :NEW.ID_INTERCONSULTA, :NEW.OTRA_DIFICULTAD, :NEW.FECHA_CREACION );
ELSE IF envbq_status = 0 THEN valor_envbq_update := 0; ELSE valor_envbq_update := 2; END IF;
UPDATE TKRBQ_ENCUESTA_DOCTOR SET ENVIO_BQ = valor_envbq_update, ID = :NEW.ID, ID_CONSULTA = :NEW.ID_CONSULTA, ID_USUARIO = :NEW.ID_USUARIO, DURACION_CONSULTA = :NEW.DURACION_CONSULTA, SATISFACCION_PRODUCTO = :NEW.SATISFACCION_PRODUCTO, EXPERIMENTO_DIFICULTADES = :NEW.EXPERIMENTO_DIFICULTADES, COMENTARIOS = :NEW.COMENTARIOS, FECHA_ENCUESTA = :NEW.FECHA_ENCUESTA, RECOMIENDA_SERVICIO = :NEW.RECOMIENDA_SERVICIO, ID_INTERCONSULTA = :NEW.ID_INTERCONSULTA, OTRA_DIFICULTAD = :NEW.OTRA_DIFICULTAD, FECHA_CREACION = :NEW.FECHA_CREACION WHERE ID = :OLD.ID AND ENVIO_BQ != 1; END IF; END IF;
-- Caso DELETE IF DELETING THEN
SELECT (SELECT ENVIO_BQ FROM TKRBQ_ENCUESTA_DOCTOR WHERE ID = :OLD.ID AND ENVIO_BQ != 1 AND ROWNUM <= 1) INTO envbq_status FROM DUAL;
IF envbq_status IS NOT NULL THEN DELETE TKRBQ_ENCUESTA_DOCTOR WHERE ID = :OLD.ID AND ENVIO_BQ != 1; END IF;
INSERT INTO TKRBQ_ENCUESTA_DOCTOR ( ENVIO_BQ, ID, ID_CONSULTA, ID_USUARIO, DURACION_CONSULTA, SATISFACCION_PRODUCTO, EXPERIMENTO_DIFICULTADES, COMENTARIOS, FECHA_ENCUESTA, RECOMIENDA_SERVICIO, ID_INTERCONSULTA, OTRA_DIFICULTAD, FECHA_CREACION
) VALUES ( -1, -- ENVIO_BQ para DELETE :OLD.ID, :OLD.ID_CONSULTA, :OLD.ID_USUARIO, :OLD.DURACION_CONSULTA, :OLD.SATISFACCION_PRODUCTO, :OLD.EXPERIMENTO_DIFICULTADES, :OLD.COMENTARIOS, :OLD.FECHA_ENCUESTA, :OLD.RECOMIENDA_SERVICIO, :OLD.ID_INTERCONSULTA, :OLD.OTRA_DIFICULTAD, :OLD.FECHA_CREACION ); END IF;
EXCEPTION WHEN OTHERS THEN vro_error.nombre_programa := 'TRG_SYNC_TKR_ENCUESTA_DOCTOR'; vro_error.nombre_metodo := 'TRIGGER_SYNC_BQ'; vro_error.parametros := 'id de consultas: '||:old.id; uti_ge_excepciones_pkg.p_grabar_log (vro_error);
END;
